import React, { useState, useEffect } from "react";
import axios from "axios";

import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  LabelList
} from "recharts";

function ModelAccuracy() {
  const [modelData, setModelData] = useState([]);

  useEffect(() => {
  axios.get("http://localhost:5050/model-performance")
    .then(res => {
      console.log(res.data); // 🔍 check
      setModelData(res.data.allModels);  // ✅ IMPORTANT FIX
    })
    .catch(err => console.error(err));
}, []);

  return (
    <div style={{ width: "90%", margin: "40px auto", textAlign: "center" }}>
      
      {/* TITLE */}
      <h2>MODEL PERFORMANCE COMPARISON: SALARY PREDICTION SYSTEM</h2>
      <p>Comparing ML Models across Key Metrics for Accuracy and Error</p>

      {/* CHART */}
      <ResponsiveContainer width="100%" height={400}>
        <BarChart data={modelData}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis domain={[0, 1]} />
          <Tooltip />
          <Legend />

          {/* Accuracy Bar */}
          <Bar dataKey="accuracy" fill="#FFA500" name="Accuracy (R²)">
            <LabelList dataKey="accuracy" position="top" />
          </Bar>

          {/* RMSE Bar */}
          <Bar dataKey="rmse" fill="#2E75B6" name="RMSE">
            <LabelList dataKey="rmse" position="top" />
          </Bar>
        </BarChart>
      </ResponsiveContainer>

      {/* TABLE BELOW CHART */}
      <table style={{ width: "80%", margin: "20px auto", borderCollapse: "collapse" }}>
        <thead>
          <tr style={{ background: "#f2f2f2" }}>
            <th style={{ padding: "10px", border: "1px solid #201f1f" }}>Model</th>
            <th style={{ padding: "10px", border: "1px solid #282727" }}>Accuracy (R²)</th>
            <th style={{ padding: "10px", border: "1px solid #2e2c2c" }}>RMSE</th>
          </tr>
        </thead>
        <tbody>
          {modelData.map((model, idx) => (
            <tr key={idx} style={{ background: model.accuracy === Math.max(...modelData.map(m => m.accuracy)) ? "#e9ede9" : "white" }}>
              <td style={{ padding: "10px", border: "1px solid #1c1b1b" }}>{model.name}</td>
              <td style={{ padding: "10px", border: "1px solid #1a1919" }}>{model.accuracy}</td>
              <td style={{ padding: "10px", border: "1px solid #141414" }}>{model.rmse}</td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* FOOTER NOTE */}
      <p style={{ marginTop: "20px", fontSize: "14px", color: "white" }}>
        Note: RMSE is scaled to 0-1 for direct visual comparison with R² Accuracy.
      </p>
    </div>
  );
}

export default ModelAccuracy;
